var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……알큐비에레 프로토콜 재가동.","JPN":"……アルクビエレプロトコール再起動。","ENG":"...Reactivating Alcubierre Protocol.","TWN":"……重新啟動協定引擎。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"TYPING_LOOP"},{"id":"L7_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"가르강튀아, 스탠바이.","JPN":"ガルガンティア、スタンバイ。","ENG":"Garguantia, on standby.","TWN":"加爾剛迪亞，預備。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"됐어! 아줌마, 준비 끝났어!","JPN":"よし！　おばさん、準備できたよ！","ENG":"There we go! Maria, it’s ready!","TWN":"OK！大嬸，準備妥當！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"끄어어…… 카페인…… 카페인을 줘……","JPN":"うおお……カフェイン……カフェインをくれ……","ENG":"Urgh... Caffeine... Give me caffeine...","TWN":"嗚嗚……咖啡因……我需要咖啡因……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"우리 엄마가…… 술 끊는 놈은 몰라도 커피 끊는 독종이랑은 엮이지 말라고 그랬는데……","JPN":"お母さんが……酒をやめる奴はともかく、コーヒーをやめるあくどい奴とは関わるなって言ったのに……","ENG":"My mom... said not to get involved with nasty people who cut off coffee...","TWN":"我媽說……戒酒、戒咖啡的人都不是什麼好東西，叫我們別跟這種人混在一起……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"수고했다, 실비아.","JPN":"ご苦労だったな、シルビア。","ENG":"Good job, Sylvia.","TWN":"辛苦你了，希爾維亞。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"별동대 쪽은 어떻지?","JPN":"別働隊の方はどうだ？","ENG":"How are the fighter squadrons doing?","TWN":"其他人呢？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 그럭저럭 시간에 맞출 수는 있을 것 같군.","JPN":"ま、どうにか間に合わせられそうだぜ。","ENG":"They should be able to make it on time.","TWN":"嗯，時間應該可以配合上吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다 때려부순다는 게 말이 쉽지, 그리 간단한 게 아니라고.","JPN":"全部叩き潰すってのは、言うほど簡単じゃねえんだ。","ENG":"Destroying the whole thing is easier said than done.","TWN":"她說要整個毀掉，話說得簡單，但沒那麼容易吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 정말 괜찮은 건가?","JPN":"しかし本当に大丈夫なのか？","ENG":"But are you sure about this?","TWN":"不過真的沒問題嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무리 세계를 주름잡는 대기업이라도 재산 손실이 만만치 않을 텐데.","JPN":"いくら世界を牛耳る大企業でも、なかなか大きな損失だろ。","ENG":"Even for such an affluent conglomerate, the financial loss will be immense.","TWN":"就算是稱霸世界的大企業，但財務損失應該會蠻可觀的喔。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요. 그만큼 더 벌면 되죠.","JPN":"大丈夫です。その分儲ければいいのですから。","ENG":"It's okay. We just need to make even more money.","TWN":"沒問題的，錢再賺就好。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이걸 만든 직원 분들의 노고는 다른 방법으로 기려야 하겠지만요.","JPN":"これを作った職員の方々のご苦労は別の方法でねぎらうべきでしょうけど。","ENG":"Although I’ll have to honor the efforts of the employees who built this in a different way.","TWN":"只是需要另外想辦法彌補辛苦打造出軌道基地的員工。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……확실히 사고 방식부터 우리와는 다르군.","JPN":"……確かに俺らとは考え方から違うな。","ENG":"...You truly think in a different way than the rest of us.","TWN":"……大企業的會長果然連思考方式都和我們不一樣呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"사장님께서 도와달라고 부탁하신 분들이니까요. 손해는 얼마든지 봐도 상관없어요.","JPN":"社長が手伝ってくれと頼んだ方々ですからね。いくら損しても構いません。","ENG":"Because the Boss asked me to help you all, I don't mind taking a loss, no matter how big.","TWN":"因為是老闆拜託我幫你們的，所以不管有多少損失都無所謂。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 얼터니움 정제를 위한 핵심 시설도 엔터프라이즈로 옮겨 뒀고요.","JPN":"あと、オルタニウムを精製するためのコア施設もエンタープライズに移しておきました。","ENG":"Also, the core facilities for refining Alternium have been transported to the Enterprise.","TWN":"另外，製造黑化永恆之金的主要設備，也已經搬到企業號上。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"회장님의 전폭적인 협조에 감사를 표하겠소.","JPN":"会長の全面的なご協力に感謝します。","ENG":"Thank you for your utmost support.","TWN":"謝謝會長的傾囊相助。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"가능하면 모든 손실을 보전해 드리고 싶지만 이번 건은…… 솔직히 자신할 수가 없군요.","JPN":"できればすべての損失を補填してさしあげたいところですが、今回の件は……正直なところ自信がありません。","ENG":"If at all possible, I’d like to recompensate you for all of your losses... But I'm not sure if that's even possible.","TWN":"可以的話，我也希望可以補償你們的損失，但……這次我實在無法保證。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이 정도 예산을 소모하겠다고 하면 의회에서 내 목을 먼저 칠 것 같으니……","JPN":"このくらいの予算を消費すると言ったら議会から私をクビにしそうですので……","ENG":"If I ask the council for this kind of funding, they’ll call for my head...","TWN":"要花這麼多的預算，我怕我在會議中會人頭不保……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요. 예산이 필요하면 주식을 사면 되거든요.","JPN":"大丈夫です。予算が必要なら株を買えばいいのです。","ENG":"No need. If I need funding, I’ll just buy more stocks.","TWN":"沒事的，需要預算的話買股票就好。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"주식?","JPN":"株？","ENG":"Stocks?","TWN":"股票？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 돈은 원래 주식에 넣어 두면 벌리잖아요?","JPN":"はい。お金というものは、株を買っておけば増えるものではありませんか？","ENG":"Yes. If you put money into stocks, it multiplies!","TWN":"是的，不是把錢拿去買股票就會賺錢嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"음……. 하지만 주식이라는 건 시장에 따라 손해도 빈번할 텐데…….","JPN":"うむ……ですが、株というものは市場によって損することも頻繁に発生するはずでは……","ENG":"Um... But the thing about stocks is that losses are also quite common depending on the market...","TWN":"嗯……但投資一定有風險，股票投資有賺有賠……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 정말요? 전 항상 돈이 불어나던데요?","JPN":"え？　本当ですか？　私はいつもお金が増えていましたけど。","ENG":"Huh? Really? It always seems to print money for me.","TWN":"是嗎？可是我每次都賺欸？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……기회가 되면 다음에 매입하실 때 어떤 걸 고르실지 꼭 듣고 싶어지는군요, 회장님.","JPN":"……機会があれば次に購入される際に、どの銘柄をお選びなのかぜひとも伺いたいものです、会長。","ENG":"...I'd love to hear which stocks you buy the next time the opportunity presents itself.","TWN":"……會長，你下次買股票時，也請跟我分享一下情報。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 그런 거라면 지금도…….","JPN":"あ、そういうことでしたら今でも……","ENG":"Oh! If you want, I can...","TWN":"我現在就可以……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"잠깐! 잠깐! 비켜 봐요!","JPN":"ちょっと！　ちょっと！　どいて！","ENG":"Wait! Wait! Get out of the way!","TWN":"等等！讓一讓！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 아가씨. 신호 주기 전까진 대화 중에 끼어들지 말라고 했잖아.","JPN":"おい、お嬢ちゃん。合図を送るまで会話に割り込むなって言っただろうが。","ENG":"Hey, young lady. Didn’t I tell you not to cut people off while they’re talking until I give you the signal?","TWN":"喂，小姐，我不是說過，在我Cue你之前不要亂插話嗎！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"그런 건 모르겠고요!","JPN":"そんなのはどうでもいいんです！","ENG":"Like I care about any of that!","TWN":"我不管啦！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"알아야 하지 않을까요……? 해피 엔딩으로 가는 선택지 같았는데요……?","JPN":"どうでもよくはないんじゃないですか……？　ハッピーエンドへの選択肢みたいだったんですけど……？","ENG":"Shouldn’t we know about this too? It seems like good ending route...","TWN":"應該要管一下吧……？感覺是通往幸福結局的選項說……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저희 정말 이번 일이 마지막 맞죠?","JPN":"私たち、本当にこれが最後の仕事なんですよね？","ENG":"Is this really the final job?","TWN":"這次任務真的是最後一次對吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이번 임무만 잘 수행하면 그냥 도망쳐도 되는 거죠?","JPN":"今度の任務さえちゃんと果たせば、逃げてもいいんですよね？","ENG":"If we complete this mission well, we can just run away, right?","TWN":"只要完成這次任務，就可以落跑對吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그래요. 무서워서 그러는 건 정말 아니고요……","JPN":"そ、そうです。本当は怖いからじゃないです……","ENG":"Th-that’s right. It’s really not because we are afraid or anything...","TWN":"對…對啊，我們可不是因為害怕喔……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아무튼 약속은 약속이니까…… 지켜야 한달까…… 그래 주시면 고맙달까……","JPN":"とにかく約束は約束ですから……守るべきというか……そうしてくれるとありがたいというか……","ENG":"Anyway, a promise is a promise... You know, it needs to be kept... And if you keep your promise, we would be grateful...","TWN":"只是既然是約定……就要遵守……先謝謝囉……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그야 물론이지. 델타세븐 체험 캠프 멤버 여러분에게도 큰 빚을 졌네.","JPN":"それはもちろんだ。デルタセブン体験キャンプのみんなにも大変お世話になったな。","ENG":"Of course. We are also indebted to the participants of the Delta Seven experience camp.","TWN":"那是當然的，參加第七三角洲體驗營的各位，我們欠你們很大的人情呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이미 충분한 도움을 받았으니 이번 작전만 끝나면 멀리 도망쳐 있다가 안전해진 뒤에 다시 합류하게나.","JPN":"もう十分助けてもらったんだ。この作戦が終わったら遠くに逃げておいて、安全になったらまた合流してくれ。","ENG":"As we’ve already received much assistance, once this mission is complete, you may run and hide somewhere safe, then rejoin us when it's safe again.","TWN":"我們已經受到你們很多的幫助，這次作戰結束後，你們可以逃得遠遠的，等安全後再會合吧！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"지금 그 말 기억했어요! 취소는 무효!","JPN":"今の言葉、絶対ですからね！　取り消しなし！","ENG":"We’ll remember that! No changing your mind later!","TWN":"是你說的喔！我記住囉！不能取消！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"혹시라도…… 거짓말이면 미, 민원 넣을 거에요……!","JPN":"もし……ウソだったら、く、苦情を入れますよ……！","ENG":"I-if you’re lying to us... I-I’m going to file a c-complaint...!","TWN":"你要是……說謊的話，我們會…生氣氣喔…！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……정신이 없군요.","JPN":"……慌ただしいですね。","ENG":"...It’s very hectic right now.","TWN":"……我真糊塗！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래도 강력한 공간 능력자가 있으니 이런 작전도 가능하네요.","JPN":"でも強力な空間能力者がいてこそ、こんな作戦もできるものです。","ENG":"Nonetheless, such a mission is only possible because we have a powerful space manipulator.","TWN":"有這麼厲害的空間高手在我們當中，這次作戰完全是可行的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"칭찬 고맙군. 그럼 시작해 볼까?","JPN":"誉め言葉、ありがとう。それでは始めるか。","ENG":"I appreciate the compliment. Now, shall we begin?","TWN":"謝謝你的稱讚，那就開始吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아, 전부 제 위치에 대기하고 있지?","JPN":"よっし、全員位置についてるな？","ENG":"All right, is everybody in position?","TWN":"好，全都就定位了吧？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금이야! 엔진 제어 센서를 전부 파괴해!","JPN":"今だ！　エンジン制御センサーを全部破壊しろ！","ENG":"Now! Destroy every single engine control sensor!","TWN":"就是現在！破壞引擎控制器！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"알았어요!","JPN":"わかりました！","ENG":"Roger that!","TWN":"收到！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"쁘, 쁘띠 라이트닝!","JPN":"ぷ、プチ・ライトニング！","ENG":"P-petite Lightning!","TWN":"輕…輕微閃擊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"각성 토미의 힘으로오오오오!","JPN":"覚醒トミーの力でええええ！","ENG":"Awakened Tommy’s streeeeeength!","TWN":"看我覺醒湯米的厲害害害害！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"다 파괴한 것 같아. 이제 어떻게 하지?","JPN":"全部壊したみてえだな。これからはどうすんだ？","ENG":"I think that’s all of them. Now what?","TWN":"好像都破壞光咧？現在要怎麼辦？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어쩌긴 뭘 어째. 달려야지.","JPN":"どうするも何も、走るぞ。","ENG":"What do you mean \\"now what\\"? We run.","TWN":"什麼怎麼辦？快跑啊！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"다, 달린다고요?","JPN":"は、走る？","ENG":"R-run?","TWN":"快…快跑？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"어째서…… 그런 불안한 대사를 하시는 거죠?","JPN":"なんで……そんな危ないセリフを言うんですか？","ENG":"Why... are you saying such an ominous thing?","TWN":"為什麼……要說那出那種令人不安的台詞呢？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"오비탈 베이스에 달린 부하제어 장치를 전부 동시에 파괴했으니 엔진이 과열될 거야.","JPN":"オービタルベースについた負荷制御装置をすべて同時に破壊したんだから、エンジンが過熱するはずだ。","ENG":"Since we destroyed all of the overheating limiter devices on the Orbital Base at the same time, the engine will overheat.","TWN":"軌道基地的負壓控制裝置已經全部同時遭到破壞，想當然引擎一定會過熱。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나라면 그런 함선에 타고 있고 싶지 않은걸?","JPN":"俺ならそんな艦船に乗りたくはねえな。","ENG":"Now I don’t know about you guys, but I sure don’t want to be on this ship much longer.","TWN":"要是我的話，才不想搭繼續搭在艦船上咧！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"하하, 함선이 엔진 좀 과열됐다고 터지기라도 하겠어?","JPN":"はは、ちょっとエンジンが過熱したくらいで艦船が爆発するわけないだろ。","ENG":"Ha ha. What? The ship is going to blow up just because the engine overheated a bit?","TWN":"哈哈，艦船的引擎稍微過熱又怎麼樣？難不成會爆炸嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"만화영화처럼 자폭장치라도 만들어 두지 않고서야……","JPN":"アニメのように自爆装置でもあるならともかく……","ENG":"Unless there’s some kind of self-destruction device on it, like in the cartoons.","TWN":"又不像電影演的，有什麼自動引爆裝置……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"이봐, 설마……","JPN":"おい、まさか……","ENG":"...Don’t tell me...","TWN":"喂，該不會……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"자폭 장치는 아니지만 엔진 코어에 얼터니움 리액터를 하나 달아 놨지.","JPN":"自爆装置じゃねえが、エンジンコアにオルタニウムリアクターを一つ付けておいたんだ。","ENG":"It’s not a self-destruction device, but I attached an Alternium Reactor on the engine core.","TWN":"是沒有自動引爆裝置啦，只是在引擎上裝一個黑化永恆之金電抗器而已。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그게 폭발하면……","JPN":"それが爆発すると……","ENG":"If that detonates...","TWN":"那個爆炸的話……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"뭐 해! 너 아직 안 달리고 있었냐?!","JPN":"何やってんだ！　お前まだ走ってねえのかよ！？","ENG":"What are you guys doing! Why aren’t you running yet?!","TWN":"傻在那做啥！腳還不趕快跑起來？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"야, 야! 같이 가!","JPN":"お、おい！　置いてくな！","ENG":"Hey, hey! Wait for me!","TWN":"喂！等我啦！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"탈출선은 반대쪽이야! 이 멍청이들아!!","JPN":"脱出船は反対側だ！　このバカたれども！！","ENG":"The exit is on the opposite side you idiots!","TWN":"你們這群蠢蛋！逃生門在反方向啦！！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흐음, 참으로 거대한 폭발이 아닌가.","JPN":"ふむ、なんとも巨大な爆発だな。","ENG":"Hmm... That was quite an explosion.","TWN":"嗯？好劇烈的爆炸？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 몸을 피하십시오.","JPN":"殿下、御身をお隠しください。","ENG":"You must evacuate, Your Highness.","TWN":"殿下，請保護龍體。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"괜찮다. 그런데 무슨 일이지?","JPN":"大丈夫だ。ところでどういうことだ？","ENG":"I’ll be fine. However, I wonder what happened.","TWN":"沒事，這是怎麼回事？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우리 기사단이 무언가 놓친 것인가? 기습의 전조는 없었거늘.","JPN":"我々の騎士団が何かを見逃したのか？　奇襲の前兆はなかったはずだ。","ENG":"Did our Order miss something? There were no signs of an ambush.","TWN":"我們騎士團有錯過什麼嗎？怎麼沒有偷襲的徵兆？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아마도…… 땅 속 깊은 곳에서 오비탈 베이스를 폭발시킨 것 같습니다.","JPN":"おそらく……深い地中からオービタルベースを爆発させたようです。","ENG":"It seems that the enemy has detonated the Orbital Base somewhere deep underground.","TWN":"似乎……已經在地底深處將軌道基地炸毀。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오, 그 거대한 함선을?","JPN":"ほう、あの巨大な艦船を？","ENG":"Oh? Is it possible to do that to such a massive ship?","TWN":"喔？那麼大艘的艦船？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 땅을 파는 광경 따위 보이지 않았다. 그리 짧은 시간에 가능한 일인가?","JPN":"だが地面を掘る光景など見えなかった。そんな短時間にできることなのか？","ENG":"But I didn’t see them digging. Is that possible in such a short amount of time?","TWN":"可是也沒看到挖地的痕跡，在這麼短的時間內有可能嗎？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"적들 중에 강력한 공간 능력자가 있다고 들었습니다.","JPN":"敵の中に強力な空間能力者がいると聞きました。","ENG":"I heard that a powerful space manipulator is among our enemies.","TWN":"我聽說在敵人之中有位空間高手。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그녀의 힘을 이용해 단숨에 함선을 땅 속으로 전이시킨 모양입니다.","JPN":"彼女の力で一気に艦船を地中へと転移させたようです。","ENG":"It seems that they have used her ability to send the ship underground instantaneously.","TWN":"我猜應該是利用她的能力，瞬間將艦船移動到地底。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"나쁘지 않은 임기응변이로군.","JPN":"悪くない策だな。","ENG":"It is not a bad move considering the circumstances.","TWN":"危機處理能力蠻不錯的。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 피해는 그리 크지 않다. 이 기습에 무슨 의미가……","JPN":"だが被害はそこまで大きくない。この奇襲に何の意味が……","ENG":"However, our losses are minimal. What purpose does this ambush serve...?","TWN":"不過損失不大，對這場偷襲的影響……"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 저것을 보십시오!","JPN":"殿下、あれをご覧ください！","ENG":"Your Highness! Over there!","TWN":"殿下，您看！"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저건…… 공간 균열인가?","JPN":"あれは……空間亀裂か？","ENG":"Hmm...? Isn’t that a space rift?","TWN":"那是……空間裂縫嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"아군에 피해를 주기 위해 함선을 파괴한 것이 아니었습니다.","JPN":"味方にダメージを与えるために艦船を破壊したわけではありませんでした。","ENG":"They didn’t destroy the ship to take out our forces.","TWN":"看來對方破壞艦船的目的，不是要對我方造成傷害。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"폭발로 발생한 에너지를 이용하여 일시적이지만 공간 균열…… 장벽을 만들어 낸 것입니다.","JPN":"爆発で発生したエネルギーを利用し、一時的ですが空間亀裂……障壁を作り上げたのです。","ENG":"They used the energy generated by the explosion to create a temporary space rift... barrier.","TWN":"而是要利用爆炸產生的能量，打造臨時空間裂縫…… 屏障。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"이건 흡사……","JPN":"これはまるで……","ENG":"This is almost like...","TWN":"這個手法就類似……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 루크레시아가 발키리를 퇴거시킨 방법과 유사하군.","JPN":"そうだ。ルクレシアがヴァルキリーを退去させた方法と似ているな。","ENG":"Yes, the method that Lucrecia used to remove the Valkyrie from the battlefield.","TWN":"沒錯，就類似露可蕾西亞擊退女武神的手法。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 짧은 시간 동안 우리의 방식을 파악하고 역공에 활용한 것인가?","JPN":"その短時間に私たちのやり方を把握し、反撃に応用したのか？","ENG":"Did they figure out our method and utilize it against us in such a short amount of time?","TWN":"他們在那麼短的時間內，就摸清楚我們的手法，還用來反擊我們嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 이대로 두면 선봉 부대가 완전히 고립될 겁니다.","JPN":"殿下、このままでは先鋒部隊が完全に孤立します。","ENG":"Your Highness, if we don’t act swiftly, the vanguard will be cut off completely.","TWN":"殿下，這樣下去，先鋒部隊會孤立無援的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"누구인지는 모르겠지만 대단한 자로군.","JPN":"誰かは知らんが、素晴らしいな。","ENG":"I don’t know who’s behind it, but that is impressive.","TWN":"雖然不知道是誰，但還蠻厲害的嘛。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"만약 적장을 사로잡게 된다면 상을 내리는 것도 좋을 것이다.","JPN":"もし敵将を捕らえることがあれば、褒美をやってもよかろう。","ENG":"If we happen to capture their general, I may consider bestowing them a reward.","TWN":"若是能活捉對方將領，我重重有賞。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"지금이다! 함대 반전!","JPN":"今だ！　艦隊反転！","ENG":"Now! Launch the counteroffensive!","TWN":"就是現在！艦隊掉頭！"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"오비탈 베이스의 폭발로 분열된 적의 선두 부대를 요격한다!","JPN":"オービタルベースの爆発で分裂された敵の先鋒部隊を迎撃する！","ENG":"Strike the enemy’s vanguard isolated by the explosion!","TWN":"攻擊軌道基地爆炸後分散的敵軍先鋒部隊！"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"제이크 대령! 준비되었나?","JPN":"ジェイク大佐！　準備はいいか？","ENG":"Colonel Jake, are you ready?","TWN":"傑克上校！準備好沒？"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"<color=#ffd34c>스톰브링거, 온라인!</color>","JPN":"<color=#ffd34c>ストームブリンガー、オンライン！</color>","ENG":"<color=#ffd34c>Stormbringer, online!</color>","TWN":"<color=#ffd34c>興風者，上線！</color>"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"<color=#ffd34c>천둥을 원하시는 곳에 손가락을 가리키기만 하십시오!</color>","JPN":"<color=#ffd34c>雷を呼びたい場所を指し示してください！</color>","ENG":"<color=#ffd34c>Just point out to me where you want the lightning to strike!</color>","TWN":"<color=#ffd34c>看你想要雷劈到哪裡，手指一下就好！</color>"},"stage":{"bg":"MS_905","bgm":"THEMA_MARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};